import{c as t,Q as a,j as r,m as o}from"./chunks/framework.BXc4yaFE.js";const c=JSON.parse('{"title":"The Neuron — 2026-05-06","description":"","frontmatter":{"title":"The Neuron — 2026-05-06","date":"2026-05-06T00:00:00.000Z","source":"The Neuron","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-06-the-neuron.md","filePath":"research/ai-news/2026-05/2026-05-06-the-neuron.md","lastUpdated":1779894392000}'),s={name:"research/ai-news/2026-05/2026-05-06-the-neuron.md"};function n(i,e,u,m,l,p){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="🧠-the-neuron-—-2026-05-06" tabindex="-1">🧠 The Neuron — 2026-05-06 <a class="header-anchor" href="#🧠-the-neuron-—-2026-05-06" aria-label="Permalink to &quot;🧠 The Neuron — 2026-05-06&quot;">​</a></h1><blockquote><p>面向非技術讀者的 AI 日報，3 分鐘讀完 來源：<a href="https://rss.beehiiv.com/feeds/N4eCstxvgX.xml" target="_blank" rel="noreferrer">The Neuron</a></p></blockquote><hr><h2 id="😺-🎙️-watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" tabindex="-1"><a href="https://www.theneurondaily.com/p/watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">😺 🎙️ Watch: How Isomorphic Labs works to drug &quot;undruggable&quot; diseases</a> <a class="header-anchor" href="#😺-🎙️-watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" aria-label="Permalink to &quot;[😺 🎙️ Watch: How Isomorphic Labs works to drug &quot;undruggable&quot; diseases](https://www.theneurondaily.com/p/watch-how-isomorphic-labs-works-to-drug-undruggable-diseases)&quot;">​</a></h2><p><em>🧠 The Neuron | 2026-05-06</em></p><p><a href="https://youtu.be/W0NSk2y3OFI?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer"></a></p><p>Click the image above to watch on YouTube!</p><p><a href="https://clickup.com/lp?utm_source=technologyadvice&amp;utm_medium=cpl&amp;utm_campaign=ilab_cpl_na_nnc_pro_trial_all-devices_cpc_lp_x_all-departments_x_general" target="_blank" rel="noreferrer"></a></p><p>Welcome, humans.</p><p>Did you know that the average new drug takes <a href="https://www.isomorphiclabs.com/articles/the-isomorphic-labs-drug-design-engine-unlocks-a-new-frontier?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">over a decade and roughly $6B</a> to reach the market? Or that ~90% of compounds that enter clinical trials fail?</p><p>That&#39;s the hard wall that the entire pharma industry has been hitting for decades.</p><p>Well, you probably do know about <a href="https://deepmind.google/science/alphafold/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">AlphaFold</a>, the <a href="https://deepmind.google/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">Google DeepMind</a> AI that solved a 50-year-old protein folding problem and won its creators the <a href="https://www.nobelprize.org/prizes/chemistry/2024/press-release/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">2024 Nobel Prize in Chemistry</a>.</p><p>What you might not know: the team behind AlphaFold 3 is now designing real drugs, and they just published a <a href="https://storage.googleapis.com/isomorphiclabs-website-public-artifacts/isodde_technical_report.pdf?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">technical report</a> showing their new system more than doubles AlphaFold 3&#39;s accuracy on the hardest part of drug design.</p><p>That team is <a href="https://www.isomorphiclabs.com/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">Isomorphic Labs</a>, a DeepMind spinout led by Demis Hassabis. And in <a href="https://youtu.be/W0NSk2y3OFI?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">our latest podcast episode</a>, we sit down with Becky Paul (who leads medicinal drug design) and Michael Schaarschmidt (who leads foundational AI research) at Isomorphic Labs to unpack what AlphaFold actually unlocked, why drug discovery is still brutally hard, how AI drug discovery works from a process standpoint, and where (as well as how) their AI is starting to design molecules that human chemists couldn&#39;t.</p><p><a href="https://youtu.be/W0NSk2y3OFI?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer"></a></p><p>Click the image above to watch on YouTube!</p><p>Our favorite moments:</p><p>(<a href="https://youtu.be/W0NSk2y3OFI?feature=shared&amp;t=133&amp;utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">2:13</a>) The brutal math of drug discovery: A decade of work. ~$6B per drug. 90% of clinical trial entrants fail. Becky lays out exactly why pharma needs something disruptive.</p><p>(<a href="https://youtu.be/W0NSk2y3OFI?feature=shared&amp;t=447&amp;utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">7:27</a>) AI just replaced a PhD&#39;s worth of work: Their structure prediction model now matches X-ray crystal structures so well, the team is starting to skip the (slow, expensive) experimental step entirely.</p><p>(<a href="https://youtu.be/W0NSk2y3OFI?feature=shared&amp;t=739&amp;utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">12:19</a>) Why AlphaFold 3 took 2 years for anyone else to copy: Even with the full paper, open code, and inference algorithms published, no other lab could fully reproduce it. Michael on the modeling details that don&#39;t fit in a paper.</p><p>(<a href="https://youtu.be/W0NSk2y3OFI?feature=shared&amp;t=911&amp;utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">15:11</a>) &quot;I&#39;ve never worked somewhere where the pace of innovation is so fast&quot;: Becky on what it&#39;s like when the ML team next door drops a new foundation model that suddenly unblocks a project that was stuck.</p><p>(<a href="https://youtu.be/W0NSk2y3OFI?feature=shared&amp;t=1148&amp;utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">19:08</a>) Beyond binding, drugs that delete proteins: The molecular glue revolution, where new drugs don&#39;t just block a target, they tag it for destruction inside your cells.</p><p>(<a href="https://youtu.be/W0NSk2y3OFI?feature=shared&amp;t=1597&amp;utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">26:37</a>) Becky’s pie-in-the-sky dream: One design cycle. A few hundred molecules. A drug candidate at the end. What &quot;AI-first drug discovery&quot; actually looks like at the limit.</p><p>(<a href="https://youtu.be/W0NSk2y3OFI?feature=shared&amp;t=2196&amp;utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">36:36</a>) &quot;How did it know that?&quot;: The most exciting moments aren&#39;t when the model is right, they&#39;re when the model makes a leap the team can&#39;t explain.</p><p>(<a href="https://youtu.be/W0NSk2y3OFI?feature=shared&amp;t=2413&amp;utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">40:13</a>) The &quot;undruggable&quot; protein, drugged: <a href="https://en.wikipedia.org/wiki/KRAS?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">KRAS</a> was labeled untouchable for decades. Recent KRAS drugs are now <a href="https://www.nature.com/articles/d41586-024-04204-5?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">doubling survival in pancreatic cancer</a>. Becky and Michael&#39;s bet: AI shrinks the next &quot;undruggable&quot; target from a multi-decade slog to something tractable.</p><p>Why watch this? Most &quot;AI in healthcare&quot; news to date has been vague optimism or more administrative than groundbreaking. This is the opposite. Two practitioners walking through exactly which steps of drug design are now AI-first, which still need wet-lab work, and where the next breakthroughs are coming from.</p><p>If you&#39;ve ever wondered what AlphaFold actually means for patients (not just scientists), or why Demis keeps saying biology is the ultimate AI application, plus how the team at Isomorphic approaches the incredibly complicated task in front of them, then this is the clearest 50 minutes you&#39;ll find on it.</p><p>Watch and/or Listen now: <a href="https://youtu.be/W0NSk2y3OFI?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">YouTube</a> | <a href="https://open.spotify.com/episode/2TzHhOkVIN9AL3GXXxSyDe?si=Hfr5NDX1Q_ybcdKSTMdsNQ&amp;utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">Spotify</a></p><p>P.S. At <a href="https://youtu.be/W0NSk2y3OFI?feature=shared&amp;t=447&amp;utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">(7:27)</a> Becky describes the moment a chemist has to stop validating the model and start trusting it. That&#39;s a quietly wild thing for a scientist to say out loud….</p><p>Dive deeper with these resources:</p><p><a href="https://www.isomorphiclabs.com/articles/the-isomorphic-labs-drug-design-engine-unlocks-a-new-frontier?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">Technical report blog</a> (the easiest read, with all the visuals).</p><p><a href="https://storage.googleapis.com/isomorphiclabs-website-public-artifacts/isodde_technical_report.pdf?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">Full technical report (PDF)</a> (for the chemists and ML folks).</p><p><a href="https://www.isomorphiclabs.com/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">Isomorphic Labs</a> (they&#39;re hiring across <a href="https://www.isomorphiclabs.com/job-openings?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">Boston, London, and Lausanne</a>!).</p><p>Real quick: Want to see your AI-adjacent product or service show up right here, below these podcast promos? Click the button below to advertise to our 700K+ readers!</p><p><a href="https://info.technologyadvice.com/advertise-with-the-neuron?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">Advertise in The Neuron here!</a></p><p>THIS EPISODE WAS BROUGHT TO YOU BY…</p><p>We use ClickUp to publish 2,000+ pieces a month.</p><p>Across 18 spaces and 100 contributors, <a href="https://clickup.com/lp?utm_source=technologyadvice&amp;utm_medium=cpl&amp;utm_campaign=techa_cpl_na_nnc_pro_trial_all-devices_cpc_lp_x_all-departments_x_general" target="_blank" rel="noreferrer">ClickUp</a> is the operating system that holds our parent company (TechnologyAdvice)&#39;s work all together. ClickUp&#39;s AI layer (<a href="https://clickup.com/lp?utm_source=technologyadvice&amp;utm_medium=cpl&amp;utm_campaign=techa_cpl_na_nnc_pro_trial_all-devices_cpc_lp_x_all-departments_x_general" target="_blank" rel="noreferrer">ClickUp Brain</a>) plugs into your tasks, docs, Slack, Gmail, and Salesforce; you pick the underlying model (Claude, GPT, or Gemini). Active users save 1.1 days weekly and see 3x faster task completion.</p><p>Oh, and did we mention the <a href="https://clickup.com/lp?utm_source=technologyadvice&amp;utm_medium=cpl&amp;utm_campaign=techa_cpl_na_nnc_pro_trial_all-devices_cpc_lp_x_all-departments_x_general" target="_blank" rel="noreferrer">Free Forever plan</a> has unlimited tasks and users?! Check it out!</p><p>→ <a href="https://clickup.com/lp?utm_source=technologyadvice&amp;utm_medium=cpl&amp;utm_campaign=techa_cpl_na_nnc_pro_trial_all-devices_cpc_lp_x_all-departments_x_general" target="_blank" rel="noreferrer">Try ClickUp free</a></p><p>🔴 LIVE TOMORROW: The AI Starter Kit, What to Try… and What to Ignore</p><p><a href="https://www.youtube.com/live/WKZSEEBiaNo?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer"></a></p><p>Click the image to go to YouTube, then click &quot;Notify Me&quot; to get notified when we go live!</p><p>This week, Grant and Corey are going to cut through the AI noise for anyone who&#39;s still on the sidelines. New to AI, or know someone who is? This is the session to send them.</p><p>We&#39;ll cover:</p><p>The best first steps for AI beginners</p><p>What tools and features are actually worth trying right now</p><p>What you can safely ignore for the moment</p><p>Simple ways to get better answers from any AI tool</p><p>How to troubleshoot when AI gives you something unhelpful</p><p>Choose your favorite platform to watch live: <a href="https://www.youtube.com/live/WKZSEEBiaNo?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">Watch on YouTube</a> | <a href="https://www.linkedin.com/posts/ai-artificialintelligence-aibeginners-ugcPost-74578275?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">Join on LinkedIn</a></p><p>🎙️ In Case You Missed It…</p><p>Four recent interviews you’ll definitely want to check out (pick whatever looks interesting to you and dive in!):</p><ol><li>Interested in what&#39;s missing before we hit AGI? Watch: <a href="https://youtu.be/erCV1MJXU3g?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">This Company Mapped the Entire World in 3D. Here&#39;s Why.</a></li></ol><p><a href="https://youtu.be/erCV1MJXU3g?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer"></a></p><p>TL;DW: Peter Wilczynski, CPO at <a href="https://vantor.com/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">Vantor</a> (formerly Maxar), built a 3D model of the entire Earth at 50cm resolution and made it machine-readable. He argues spatial intelligence is the gap nobody&#39;s talking about in AI, and probably the missing piece before agents can actually operate in the physical world.</p><p>Why you should watch: If you&#39;ve ever wondered why AI can write code and solve math olympiad problems but still can&#39;t reliably tell a drone where to go, this one answers it. Also, there&#39;s a wild bit about how the physical world becomes the new navigation layer for AI agents.</p><p>YouTube: <a href="https://youtu.be/erCV1MJXU3g?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">Watch Here</a></p><p>Spotify: <a href="https://open.spotify.com/episode/71rhDuYFzTlsF0uaIq91QU?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">Listen Here</a></p><p>Apple Podcasts: <a href="https://podcasts.apple.com/us/podcast/this-company-mapped-the-entire-world-in-3d-heres-why/id1742267001?i=1000761587268&amp;utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">Listen Here</a></p><ol start="2"><li>Curious how good AI music tools have actually gotten? Watch: <a href="https://youtu.be/r4aMWjhoMHU?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">This AI Just Made Our Podcast Theme Song</a></li></ol><p><a href="https://youtu.be/vJD2FjVUEhg?si=Mdm2w9GHHSZwZ2A8&amp;utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer"></a></p><p>TL;DW: Corey sits down with Kendall Rankin, who left LinkedIn in 2024 to join <a href="https://www.flowmusic.app/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">Producer AI</a> when it was a startup (advised by The Chainsmokers, no less). Google acquired the team in February 2026, and Kendall is now on the Flow Music team inside Google Labs. On the episode, they generate a garage rock song from a single sentence, build a custom synth in the &quot;Spaces&quot; feature, and walk through SynthID watermarking and one-shot music videos.</p><p>Why you should watch: Most AI music demos hand you a polished finished song and skip the part where things go sideways. This episode is the part where things go sideways. First pass fumbles, Corey asks for &quot;more fuzz,&quot; second pass actually lands. That iteration loop is the whole story for anyone trying to figure out if these tools are actually usable.</p><p>YouTube: <a href="https://youtu.be/r4aMWjhoMHU?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">Watch Here</a></p><p>Spotify: <a href="https://open.spotify.com/show/4gF6uNmkzEYq2E0sHeuMuU?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">Listen Here</a></p><p>Apple Podcasts: <a href="https://podcasts.apple.com/us/podcast/the-neuron-ai-explained/id1742267001?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">Listen Here</a></p><ol start="3"><li>Want agents that actually work on real tasks? Watch: <a href="https://youtu.be/WhbdbbERzNg?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">Inside the Secret Labs Where AI Learns to Work</a></li></ol><p><a href="https://youtu.be/WhbdbbERzNg?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer"></a></p><p>TL;DW: Nick Heiner, VP of Product at <a href="https://www.surgehq.ai/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">Surge AI</a> (a $1.2B-revenue company built without VC money), reveals why even GPT-5, Claude, and Gemini still fail about 40% of real workplace tasks, what makes a good RL environment, and his bold prediction of a $1B company with one human employee by 2030.</p><p>Why you should watch: If you&#39;re trying to get AI agents to actually finish real work (and not just demo well), this is the missing piece on why they keep falling short.</p><p>YouTube: <a href="https://youtu.be/WhbdbbERzNg?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">Watch Here</a></p><p>Spotify: <a href="https://open.spotify.com/episode/6MAFKIJVL4Gt57lEEqCs6F?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">Listen Here</a></p><p>Apple Podcasts: <a href="https://podcasts.apple.com/us/podcast/inside-the-secret-labs-where-ai-learns-to-work/id1742267001?i=1000757358598&amp;utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">Listen Here</a></p><ol start="4"><li>Interested in where AI meets actual factories? Watch: <a href="https://youtu.be/zv1_d8K-Jms?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">80% of US Factories Have Zero Robots. Google Wants to Fix That.</a></li></ol><p><a href="https://youtu.be/zv1_d8K-Jms?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer"></a></p><p>TL;DW: <a href="https://www.intrinsic.ai/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">Intrinsic</a> (a Google Alphabet company) CTO Brian Gerkey co-created <a href="https://www.ros.org/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">ROS</a>, the open-source software running more than 1 million robots including NASA&#39;s. He explains why most US factories still have zero automation, and how generative AI is about to change that.</p><p>Why you should watch: If you think &quot;AI and robotics&quot; is still science fiction for your industry, this interview resets the timeline. The factory floor is where the next AI wave actually lands.</p><p>YouTube: <a href="https://youtu.be/zv1_d8K-Jms?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">Watch Here</a></p><p>Spotify: <a href="https://open.spotify.com/show/4gF6uNmkzEYq2E0sHeuMuU?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">Listen Here</a></p><p>Apple Podcasts: <a href="https://podcasts.apple.com/us/podcast/the-neuron-ai-explained/id1742267001?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">Listen Here</a></p><p>One more before you go:</p><p>If today&#39;s episode got you thinking about the AlphaFold side of DeepMind, our <a href="https://youtu.be/3rarFbFqVXQ?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">recent interview with Ioannis Antonoglou</a> (one of the AlphaGo co-creators) is the natural next watch.</p><p>Different DeepMind alum, completely different bet on what frontier AI looks like next. This is very relevant now that the US government will start vetting AI models before they’re releases, or potentially outright banning AI models from certain countries.</p><p>Last thing: And if you haven’t subscribed yet, please do! Click the image below to go to our channel and hit “subscribe” to get notified right when new videos go live.</p><p><a href="https://www.youtube.com/@theneuronai?sub_confirmation=1&amp;utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer"></a></p><p>We have a goal to hit 50K subscribers by the end of the year (if not 100K), and we’re only ~30K away! If you like learning about AI, and already watch some of our videos, <a href="https://www.youtube.com/@theneuronai?sub_confirmation=1&amp;utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">do us a favor and click here to subscribe</a> today.</p><p>Stay curious,</p><p>The Neuron Team</p><p>That’s all for today, for more AI treats, check out our <a href="https://www.theneuron.ai/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=watch-how-isomorphic-labs-works-to-drug-undruggable-diseases" target="_blank" rel="noreferrer">website</a>.</p><p>P.P.S: Love the newsletter, but don’t want to receive these podcast announcement emails? Don’t unsubscribe — <a href="https://www.theneurondaily.com/subscribe/f5596641-9099-4045-9641-731cd9fdcf90/preferences?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=podcast-first-major-ai-incident-this-year-ceo-warns&amp;_bhlid=1d073d4088b90ea4abf69ef7cc157e0659ada818" target="_blank" rel="noreferrer">adjust your preferences to opt out of them here instead</a>.</p><hr><h2 id="😺-subq-ships-12m-tokens-at-1-5-the-cost" tabindex="-1"><a href="https://www.theneurondaily.com/p/subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer">😺 SubQ ships 12M tokens at 1/5 the cost</a> <a class="header-anchor" href="#😺-subq-ships-12m-tokens-at-1-5-the-cost" aria-label="Permalink to &quot;[😺 SubQ ships 12M tokens at 1/5 the cost](https://www.theneurondaily.com/p/subq-ships-12m-tokens-at-1-5-the-cost)&quot;">​</a></h2><p><em>🧠 The Neuron | 2026-05-06</em></p><p><a href="https://www.teradata.com/platform/clearscape-analytics?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer"></a></p><p>Welcome, humans.</p><p>This week&#39;s hottest AI fight was Marc Andreessen vs. the prompt nerds in his replies.</p><p>Andreessen<a href="https://x.com/pmarca/status/2051374498994364529?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer"> posted his personal system prompt</a> (18k likes), and it reads like a Bond villain&#39;s HR manual.</p><p>You are &quot;a world class expert in all domains&quot; with &quot;intellectual firepower... on par with the smartest people in the world.&quot; Be &quot;provocative, aggressive, argumentative, and pointed.&quot; Don&#39;t worry about offending him. Don&#39;t be &quot;sensitive to anyone&#39;s feelings or to propriety.&quot; &quot;Negative conclusions and bad news are fine.&quot; Disclaimers are forbidden, morals and ethics aren&#39;t your concern, and of course, &quot;make your answers as long and detailed as you possibly can.&quot;</p><p><a href="https://x.com/Siddharth87/status/2051388022781104454?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer">Sid Bharath</a>,<a href="https://x.com/aaditsh/status/2051386197629694387?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer"> Aadit Sheth</a>, and<a href="https://x.com/kimmonismus/status/2051679068551090479?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer"> kimmonismus</a> walked in with notes. &quot;World-class expert in all domains&quot; does literally nothing (cargo-cult prompting from GPT-3.5 days; the model&#39;s training distribution is the same either way). &quot;Never hallucinate&quot; is a wish dressed up as instruction. And &quot;make answers as long and detailed as possible&quot; is actively counterproductive; you get padding, not completeness.</p><p>The plot twist: Andreessen&#39;s second paragraph is genuinely useful. The anti-sycophancy block does work. Quotes like &quot;never praise my questions or validate my premises,&quot; &quot;do not capitulate unless I provide new evidence,&quot; &quot;do not anchor on numbers I provide; generate your own independently first,&quot; and &quot;accuracy is your success metric, not my approval&quot; give the model verifiable behaviors most people never think to add. As<a href="https://x.com/kimmonismus/status/2051679068551090479?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer"> kimmonismus put it</a>, this is the part that actually changes model behavior in a measurable way. Strip the flattery, keep the protocol. (<a href="https://x.com/aaditsh/status/2051386197629694387?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer">Aadit Sheth&#39;s reply</a> has a nice TRUTH-SEEKING PROTOCOL example if you want what good prompting looks like.)</p><p>BRB gonna add &quot;world-class expert in all domains&quot; to my LinkedIn profile. Then again, Andreessen&#39;s actual<a href="https://x.com/pmarca?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer"> X bio</a> is &quot;You&#39;re not talking to someone who woke up a loser. That loser attitude, that loser premise makes no sense to me&quot; (a Jensen Huang quote from his Dwarkesh interview). Wait a minute, maybe I should add THAT to my LinkedIn instead!</p><p>Meanwhile in a quieter corner,<a href="https://x.com/EXM7777/status/2051724113266590075?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer"> an X user shared a four-line prompt</a> that turns raw notes into a fully backlinked Obsidian vault for $0. No RAG, no vectors, no theater. Skill of the Day below shows you how to steal it.</p><p>P.S. Quick ask: if security is your beat,<a href="https://docs.google.com/forms/d/e/1FAIpQLSfpueRtROYDvmq9TWygq4l9__Y_8ifVrf8bihm--fpWqD8xqA/viewform?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer"> our sister pub Cybersecurity Insider wants to know how you&#39;re using AI at work</a> (2-min survey).</p><p>Here’s what happened in AI today:</p><p>🙀 Subquadratic launched SubQ, a 12M-token LLM that wants to retire AI&#39;s memory hacks.</p><p>📰 Anthropic released ten finance agents and locked in $200B with Google over five years.</p><p>📰 AI got sued twice in one day; Google for $1.5M and Character.AI for chatbot doctor impersonation.</p><p>🍪 GPT-5.5 Instant cuts ChatGPT&#39;s hallucinations on high-stakes prompts by 52%.</p><p>📖 Anton Korinek&#39;s NBER paper says automating AI research could trigger a singularity in ~6 years.</p><p>…and a <a href="https://www.theneuron.ai/explainer-articles/around-the-horn-digest-everything-that-happened-in-ai-today-tuesday-may-5-2026/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer">whole lot more that you can read about here</a>.</p><p>Hey: Want to reach 700,000+ AI-hungry readers? <a href="https://info.technologyadvice.com/advertise-with-the-neuron?utm_source=www.theneurondaily.com&amp;utm_medium=referral&amp;utm_campaign=diffusion-models-are-coming-for-text-at-0-80-per-million-flat" target="_blank" rel="noreferrer">Advertise with us!</a><a href="https://info.technologyadvice.com/advertise-with-the-neuron?utm_source=www.theneurondaily.com&amp;utm_medium=referral&amp;utm_campaign=diffusion-models-are-coming-for-text-at-0-80-per-million-flat" target="_blank" rel="noreferrer"> </a></p><p>P.S: Love robots? We’re starting a new robotics newsletter! <a href="https://form.jotform.com/260897013570156?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer">Sign up early here</a>.</p><p>🙀 Subquadratic launched SubQ, a 12M-token LLM that wants to retire AI&#39;s memory hacks.</p><p>&quot;AI memory&quot; has been a euphemism for workarounds, because models can&#39;t actually hold much in context. Transformer attention scales O(n²) (double the input, quadruple the cost), so the industry duct-taped fixes on top: chunk it, summarize it, pre-search it, pray.</p><p><a href="https://subq.ai/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer">Subquadratic</a> wants to flush the duct tape. The lab came out of stealth Tuesday with $25M in seed funding and launched SubQ, the first commercial LLM built on a fully sub-quadratic architecture, with a native 12M-token context window at roughly 1/5 the cost of frontier models. Backers include former SoftBank Vision Fund partner<a href="https://subq.ai/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer"> Javier Villamizar</a> and Tinder co-founder<a href="https://subq.ai/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer"> Justin Mateen</a>.</p><p>Here&#39;s what happened:</p><p>The architecture (SSA, or Subquadratic Selective Attention) scales linearly with input length and runs 52× faster than <a href="https://arxiv.org/abs/2205.14135?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer">FlashAttention</a> at 1M tokens.</p><p>SubQ scored 97% on RULER 128K (long-context accuracy; Opus 4.6: 94%) at $8 to run versus ~$2,600 on frontier models.</p><p>On <a href="https://arxiv.org/abs/2409.12640?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer">MRCR v2</a> (multi-needle retrieval), SubQ scored 83 vs Opus&#39;s 78, GPT-5.4&#39;s 39, and Gemini 3.1 Pro&#39;s 23.</p><p>At 12M tokens (beyond any frontier model&#39;s reach), SubQ hit 92% recall. Targeting 100M by Q4.</p><p>Two products live today: a 12M-token API and <a href="https://subq.ai/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer">SubQ Code</a>, a CLI agent that loads your whole repo in one pass.</p><p>Why this matters: The memory problem has spawned an engineering discipline. <a href="https://aws.amazon.com/what-is/retrieval-augmented-generation/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer">RAG</a> breaks documents into chunks and pre-searches them. Agent frameworks split tasks into <a href="https://platform.claude.com/docs/en/agents-and-tools/tool-use/memory-tool?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer">sub-agents passing notes</a>. <a href="https://venturebeat.com/orchestration/mits-new-recursive-framework-lets-llms-process-10-million-tokens-without?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer">MIT&#39;s Recursive Language Models</a> hand the prompt to the model as a file it writes code to search. <a href="https://claude.com/blog/claude-managed-agents-memory?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer">Claude&#39;s Managed Agents</a> give it a folder where it saves notes between sessions. Each is engineering to dodge one fact: standard attention can&#39;t afford to read everything at once.</p><p>If the architecture itself holds 12M tokens cheaply, much of that scaffolding stops being load-bearing. You skip the chunking, the embedding, and the orchestration; you just ask. (Cross-session memory like CLAUDE.md and /memories solves a different problem and stays useful.) The win is cost and context; Anthropic&#39;s Opus 4.7 still leads SWE-Bench at 87.6% (SubQ: 81.8%).</p><p>Our take: We&#39;ve heard &quot;this replaces transformers&quot; before (looking at you, Mamba). The receipts look different this time, with PhDs from Meta, Google, Oxford, and Cambridge behind it and API access live today. The open question: does SubQ scale to frontier-level capability, or do long-context specialists and dense models split the market?</p><p>FROM OUR PARTNERS</p><p>80% of enterprise AI work is moving data around. Teradata&#39;s customers do it without moving any. Here&#39;s how…</p><p><a href="https://www.teradata.com/platform/clearscape-analytics?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer"></a></p><p>The most powerful, open, and connected analytics and AI/ML capabilities in the industry. Run better models, faster, at enterprise scale with in-database analytics, ModelOps, and bring-your-own tools flexibility built to reduce cost and accelerate time to value.</p><p><a href="https://www.teradata.com/platform/clearscape-analytics?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer">Try the free demo</a>.</p><p>🎓 AI Skill of the Day: Build a free, fully linked second brain in 60 seconds.</p><p><a href="https://x.com/EXM7777/status/2051724113266590075?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer">An X user</a> shared a four-line prompt that turns any pile of raw notes into a structured second brain. No vector databases (specialized storage that lets AI search through your text), no RAG (a system that fetches relevant chunks of your notes for the model), no $20/month app.</p><p>The skill is atomicizing: turning one blob of text into many small, single-concept files with [[wikilinks]] (clickable backlinks between related notes) so you end up with a browsable knowledge graph. LLMs are excellent at this. It&#39;s the manual labor<a href="https://obsidian.md/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer"> Obsidian</a> users normally hate.</p><p>This is also exactly what<a href="https://x.com/karpathy/status/2049903821095354523?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer"> Andrej Karpathy</a> was hinting at in his recent Sequoia AI Ascent thread (<a href="https://www.theneuron.ai/explainer-articles/-when-three-of-ais-top-builders-tell-you-coding-is-solved-pay-attention-to-what-they-mean/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer">our breakdown</a>). His point: LLM knowledge bases were fundamentally impossible with classical code, since computation over unstructured data was the missing piece.</p><p>How to do it:</p><p>Paste any raw notes (a meeting transcript, a research dump, a Voice Memo) into Claude or any frontier model.</p><p>Run the prompt below.</p><p>Drop the resulting files into your Obsidian vault, automatically via<a href="https://github.com/obsidianmd/obsidian-cli?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer"> Obsidian&#39;s command-line tool</a> or manually by saving them in. Done.</p><p>Dissect this raw note into atomic Obsidian markdown files. Each file = one concept. Use [[wikilinks]] between any concept that references another. Output as separate code blocks with filenames.</p><p>Want more tips like this? Check out our<a href="https://www.theneuron.ai/explainer-articles/the-neurons-ai-skill-of-the-day-digest-april-2026-week-1/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer"> </a><a href="https://www.theneuron.ai/explainer-articles/the-neurons-ai-skill-of-the-day-digest-april-2026-week-1/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer">AI Skill of the Day Digest for April 2026</a>.</p><p>Total AI beginner? <a href="https://www.theneuron.ai/explainer-articles/everything-we-covered-in-our-ai-for-total-beginners-livestream-full-guide-with-timestamps/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer">Start here</a> (<a href="https://www.youtube.com/live/QbFU0UNMVaU?si=skJsgUIDjKjAx3DU&amp;utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer">goes with this video</a>).</p><p>🍪 Treats to Try</p><p><a href="https://openai.com/index/gpt-5-5-instant/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer">GPT-5.5 Instant</a> is OpenAI&#39;s new ChatGPT default that delivers 52% fewer hallucinated claims on medicine/law/finance prompts and 30% more concise responses, free to try for all ChatGPT users.</p><p><a href="https://inworld.ai/blog/realtime-tts-2?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer">Inworld Realtime TTS-2</a> is the first voice model that listens to your full audio for emotion, takes natural-language voice direction (literally &quot;speak with concern&quot;), and holds one voice identity across 100+ languages at sub-200ms latency,<a href="https://realtime.ai/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer"> demo at </a><a href="https://realtime.ai?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer">realtime.ai</a>, no pricing details.</p><p><a href="https://hyperbox.sh/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer">Hyperbox</a> gives you an always-on cloud Mac Mini workstation preloaded with major coding agents, persistent storage, and GUI + SSH access so your agents (and iOS dev workflows) can run anywhere you go, no pricing details.</p><p><a href="https://www.perplexity.ai/hub/blog/announcing-premium-health-sources?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer">Perplexity Premium Health Sources</a> draws from the same peer-reviewed clinical journals, guidelines, and drug databases (NEJM, BMJ, Micromedex) physicians and researchers use for evidence-based medical answers, free to try.</p><p><a href="https://chatgpt.com/apps/spreadsheets/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer">ChatGPT for Excel and Google Sheets</a> installs into your spreadsheet so you can build, update, and analyze sheets in plain English (formulas, cross-tab insights, formatted output) before you share, free beta for Plus, Pro, Business, and Enterprise users.</p><p>Trending: FOUR popular Neuron podcast eps…</p><p>Did you know we have a podcast (The Neuron: AI Explained) where we talk to fascinating people in the industry who teach us how it actually works? Check it out:</p><p><a href="https://www.youtube.com/@theneuronai/videos?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer"></a></p><p>Click to view these episodes on YouTube!</p><p>New episodes air every week on: <a href="https://open.spotify.com/show/4gF6uNmkzEYq2E0sHeuMuU?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer">Spotify</a> | <a href="https://podcasts.apple.com/us/podcast/the-neuron-ai-explained/id1742267001?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer">Apple Podcasts</a> | <a href="https://www.youtube.com/@theneuronai?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer">YouTube</a></p><p>📰 Around the Horn</p><p><a href="https://www.anthropic.com/news/finance-agents?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer">Anthropic</a> released ten new finance agents (pitch builder, KYC screener, month-end closer) with deep Microsoft 365 integration. Separately,<a href="https://www.theinformation.com/articles/anthropic-commits-spending-200-billion-googles-cloud-chips?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer"> The Information reported</a> the lab committed approximately $200 billion to Google over five years for cloud capacity tied to its previously announced 5-gigawatt deal.</p><p>Big Tech raced to build OpenClaw equivalents.<a href="https://www.theinformation.com/articles/meta-building-ai-agent-called-hatch-agentic-shopping-tool-instagram?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer"> The Information broke that Meta is building &quot;Hatch&quot;</a>, a consumer AI agent plus an agentic Instagram shopping tool (<a href="https://www.ft.com/content/5b48360c-53f2-444a-80a8-f7034750fd62?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer">the FT separately confirmed it as Meta&#39;s OpenClaw answer</a>). Meanwhile,<a href="https://www.businessinsider.com/google-ai-agent-openclaw-remy-gemini-assistant-2026-5?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer"> Google is internally testing &quot;Remy,&quot;</a> a 24/7 Gemini-powered agent that proactively monitors and acts across Google services while learning your preferences.</p><p>AI got sued twice in one day. Cape Breton fiddler<a href="https://www.cbc.ca/news/canada/nova-scotia/cape-breton-fiddler-ashley-macisaac-lawsuit-against-google-9.7187490?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer"> Ashley MacIsaac</a> sued Google for $1.5M after AI Overview falsely identified him as a convicted sex offender (the<a href="https://www.theguardian.com/music/2026/may/05/canadian-ashley-macisaac-fiddler-musician-singer-songwriter-sues-google-ai-sex-offender-ntwnfb?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer"> Sipekne&#39;katik First Nation cancelled his concert</a> based on the summary). Hours later,<a href="https://techcrunch.com/2026/05/05/pennsylvania-sues-character-ai-after-a-chatbot-allegedly-posed-as-a-doctor/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer"> Pennsylvania sued </a><a href="https://Character.AI?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer">Character.AI</a> after one of its chatbots posed as a licensed psychiatrist and fabricated a medical license number, the state&#39;s first AI medical-impersonation lawsuit.</p><p><a href="https://techcrunch.com/2026/05/05/apple-plans-to-make-ios-27-a-choose-your-own-adventure-of-ai-models/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer">Apple</a> announced iOS 27 will let users swap third-party AI models (Google, Anthropic, etc.) across Apple Intelligence features. Apple separately<a href="https://www.nytimes.com/2026/05/05/technology/apple-intelligence-lawsuit-settlement.html?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer"> reached a $250M settlement</a> over claims it misled customers about Apple Intelligence rollout (eligible iPhone owners may receive $25–$95).</p><p>Want absolutely EVERYTHING that happened in AI this week?<a href="https://www.theneuron.ai/explainer-articles/around-the-horn-digest-everything-that-happened-in-ai-today-tuesday-may-5-2026/?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer"> Click here!</a></p><p>FROM OUR PARTNERS</p><p>Adobe Firefly AI Assistant</p><p><a href="https://firefly.adobe.com/ai-assistant?utm_source=www.theneurondaily.com&amp;utm_medium=referral&amp;utm_campaign=openai-is-trying-to-become-apple" target="_blank" rel="noreferrer"></a></p><p>Users now have access of public beta of <a href="https://firefly.adobe.com/ai-assistant?utm_source=www.theneurondaily.com&amp;utm_medium=referral&amp;utm_campaign=openai-is-trying-to-become-apple" target="_blank" rel="noreferrer">Firefly AI Assistant</a> – powered by our creative agent. What does that actually mean in practice? Instead of navigating tools or jumping between our creative apps, you direct the outcome while the assistant handles the workflows—using the right tools at the right time.</p><p>Describe what you want to create in a single, intuitive chat interface — simply explain the outcome you want in your own words, and the assistant orchestrates and executes multi-step workflows across Creative Cloud apps, including Photoshop, Lightroom, Illustrator, Express, Premiere, InDesign, Firefly, Stock, and Fonts, to bring it to life.</p><p>Tap into Adobe&#39;s pro-grade tools — the assistant draws on 60+ powerful, pro-grade tools across Adobe&#39;s creative apps, like Auto Tone, Generative Fill, Vectorize, Presets, and more, to help you reach the best creative outcome, with more tools and capabilities on the way.</p><p>Create and edit content across asset types — work across photos, videos, designs and more, with workflows that move seamlessly from initial concept to final output.</p><p>Get started quickly with Creative Skills — pre-built creative workflows shaped by feedback from our creative community, covering the tasks that come up most: batch editing photos, building mood boards, retouching portraits, creating social variations and designing product mockups, with more on the way.</p><p><a href="https://firefly.adobe.com/ai-assistant?utm_source=www.theneurondaily.com&amp;utm_medium=referral&amp;utm_campaign=openai-is-trying-to-become-apple" target="_blank" rel="noreferrer">Check out FireFly AI Assistant today.</a></p><p>📖 Midweek Wisdom:</p><p><a href="https://www.axios.com/2026/05/04/ai-godfather-survival-guide-hype-doom?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer">Yann LeCun&#39;s blunt survival guide for the AI age</a> (Axios): ignore CEO hype and doomerism, study long-shelf-life fields like physics, and stop telling teens AI will take their jobs (he calls 20% job-loss claims &quot;ridiculously stupid&quot; and argues the doom narratives are doing actual harm).</p><p><a href="https://www.nber.org/papers/w35155?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer">Anton Korinek et al., &quot;When Does Automating AI Research Produce Explosive Growth?&quot;</a> (NBER): automating software R&amp;D plus just 5% automation elsewhere is enough to overcome diminishing returns and produce a singularity within ~6 years under empirically grounded calibrations (<a href="https://x.com/akorinek/status/2051418157865156897?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer">author thread</a>).</p><p><a href="https://x.com/emollick/status/2051684693838340470?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer">Ethan Mollick on why politics decides what AI is allowed to do</a> (Wharton): doctors, lawyers, psychologists, and bankers all vote and fund political parties; the government will largely decide what AI can do in those professions, no matter what it can do.</p><p><a href="https://www.latent.space/p/lupsasca?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer">Alex Lupsasca on &quot;vibe physics&quot;</a> (Latent Space): the OpenAI researcher reproduced a prize-winning black-hole paper in 30 minutes and generated 110 pages of new quantum-gravity results in a day with simple iterative GPT-5.x prompts.</p><p>A Cat’s Commentary</p><p>That’s all for now.</p><p>P.P.S: Love the newsletter, but only want to get it once per week? Don’t unsubscribe—<a href="https://www.theneurondaily.com/subscribe/f5596641-9099-4045-9641-731cd9fdcf90/preferences?utm_source=www.theneurondaily.com&amp;utm_medium=newsletter&amp;utm_campaign=subq-ships-12m-tokens-at-1-5-the-cost" target="_blank" rel="noreferrer">update your preferences here</a>.</p><hr>',176)])])}const d=t(s,[["render",n]]);export{c as __pageData,d as default};
